import React, { useState, useCallback } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import Webinars from './components/Webinars';
import UpcomingSessions from './components/UpcomingSessions';
import Newsletter from './components/Newsletter';
import WhyChoose from './components/WhyChoose';
import Footer from './components/Footer';
import { LoginModal, RegisterModal } from './components/Modals';
import Toast from './components/Toast';

export default function App() {
  const [modal, setModal] = useState(null);
  const [toast, setToast] = useState({ visible: false, message: '' });

  const showToast = useCallback((msg) => {
    setModal(null);
    setToast({ visible: true, message: msg });
  }, []);

  const hideToast = useCallback(() => setToast(t => ({ ...t, visible: false })), []);

  return (
    <>
      <Navbar
        onLogin={() => setModal('login')}
        onRegister={() => setModal('register')}
      />

      <main>
        <Hero onRegister={() => setModal('register')} />
        <Webinars onStart={(title) => showToast(`Starting "${title}" — welcome!`)} />
        <UpcomingSessions onNotify={(title) => showToast(`You'll be notified when "${title.length > 28 ? title.slice(0,28)+'…' : title}" launches!`)} />
        <Newsletter onSubscribe={() => showToast('Subscribed! You\'ll never miss an event.')} />
        <WhyChoose />
      </main>

      <Footer />

      {modal === 'login' && (
        <LoginModal
          onClose={() => setModal(null)}
          onSwitch={() => setModal('register')}
          onSuccess={() => showToast('Logged in — welcome back!')}
        />
      )}
      {modal === 'register' && (
        <RegisterModal
          onClose={() => setModal(null)}
          onSwitch={() => setModal('login')}
          onSuccess={() => showToast('Account created — welcome to Seniorly!')}
        />
      )}

      <Toast message={toast.message} visible={toast.visible} onHide={hideToast} />
    </>
  );
}
